scwin.f_CreateDataSet = function (row) {
  $c.gus.cfCopyDataMap($p, dma_selldecunsetaggr_con, dma_selldecunsetdetail_con);
  if ($c.gus.cfIsChecked($p, chb_detailAllYn)) {
    if (dma_selldecunsetdetail_con.get("aggbilgClntNo") != null && dma_selldecunsetdetail_con.get("aggbilgClntNo") != "") {
      if ($c.gus.cfIsChecked($p, chb_crnYn)) {
        dma_selldecunsetdetail_con.set("crnYn", "Y");
      } else {
        dma_selldecunsetdetail_con.set("crnYn", "N");
      }
    } else {
      dma_selldecunsetdetail_con.set("crnYn", "");
    }
  } else {
    if (row != undefined && row >= 0) {
      dma_selldecunsetdetail_con.set("aggbilgClntNo", ds_selldecunsetaggr.getCellData(row, "bilgClntNo"));
      dma_selldecunsetdetail_con.set("aggsellItemCd", ds_selldecunsetaggr.getCellData(row, "sellItemCd"));
      dma_selldecunsetdetail_con.set("aggtaxnClsCd", ds_selldecunsetaggr.getCellData(row, "taxnClsCd"));
    }
  }
  if ($c.gus.cfIsChecked($p, chb_sumDc)) {
    dma_selldecunsetdetail_con.set("sumQryYn", "Y");
  } else {
    dma_selldecunsetdetail_con.set("sumQryYn", "N");
  }
};
