scwin.gr_selldecunsetdetail_onheaderclick = function (columnIndex, columnId) {
  if (columnId == "chk") {
    let allChecked = true;
    for (let i = 0; i < ds_selldecunsetdetail.getRowCount(); i++) {
      if (ds_selldecunsetdetail.getCellData(i, "chk") != "T") {
        allChecked = false;
        break;
      }
    }
    if (!allChecked) {
      for (let i = 0; i < ds_selldecunsetdetail.getRowCount(); i++) {
        if (ds_selldecunsetdetail.getCellData(i, "dcsnClsCd") == "1") {
          ds_selldecunsetdetail.setCellData(i, "chk", "T");
        }
      }
    } else {
      for (let i = 0; i < ds_selldecunsetdetail.getRowCount(); i++) {
        ds_selldecunsetdetail.setCellData(i, "chk", "F");
      }
    }
  }
};
scwin.gr_selldecunsetdetail_oncloseup = function (rowIndex, columnIndex, columnId) {
  let row = ds_selldecunsetdetail.getRowPosition();
  let sellGoodsPatternCd = ds_selldecunsetdetail.getCellData(row, "sellGoodsPatternCd");
  if (columnId == "sellGoodsPatternCd") {
    if (sellGoodsPatternCd == "02") {
      ds_selldecunsetdetail.setCellData(row, "sellCommNo", "");
      // TODO: f_openPopUpCommInfo
    } else if (sellGoodsPatternCd == "03") {
      // TODO: f_openPopUpKndVehcl
    } else {
      ds_selldecunsetdetail.setCellData(row, "sellCommNo", "");
      ds_selldecunsetdetail.setCellData(row, "sellCommNm", "");
    }
  } else if (columnId == "sellUnitCd") {
    for (let i = 0; i < ds_unitCd.getRowCount(); i++) {
      if (ds_selldecunsetdetail.getCellData(row, "sellUnitCd") == ds_unitCd.getCellData(i, "cd")) {
        ds_selldecunsetdetail.setCellData(row, "unitClsCd", ds_unitCd.getCellData(i, "upperCd"));
        break;
      }
    }
    // TODO: f_AmtSet
  } else if (columnId == "taxnClsCd") {
    if (ds_selldecunsetdetail.getCellData(row, "taxnClsCd") == "01") {
      ds_selldecunsetdetail.setCellData(row, "vatAmt", Math.round(ds_selldecunsetdetail.getCellData(row, "sellAmt") * 0.1));
    } else {
      ds_selldecunsetdetail.setCellData(row, "vatAmt", 0);
    }
  }
};
